+use crate::error::{Error, Result};
+use crate::tcb::verify_tcb_info;
+
+pub fn verify_qe_identity(
+    qe_identity: &str,
+    qe_identity_signature: &str,
+    qe_identity_issuer_chain: &str,
+) -> Result<()> {
+    // QE Identity collateral is signed by Intel using the same signed JSON
+    // structure as TCB info. Reuse the existing certificate-chain and signed
+    // payload verification logic instead of consuming it unsigned.
+    verify_tcb_info(qe_identity, qe_identity_signature, qe_identity_issuer_chain)
+        .map_err(|_| Error::InvalidQeIdentity)
+}
