+/**
+ * Count parameters in a URL-encoded body up to a limit.
+ *
+ * Returns the total count when within the limit, otherwise undefined.
+ *
+ * @param {string} body
+ * @param {number} limit
+ * @private
+ */
+
+module.exports = parameterCount
+
+function parameterCount (body, limit) {
+  var count = 0
+  var index = 0
+
+  if (body.length === 0) {
+    return 0
+  }
+
+  while ((index = body.indexOf('&', index)) !== -1) {
+    count++
+    index++
+
+    if (count >= limit) {
+      return undefined
+    }
+  }
+
+  return count + 1
+}

