+  switch (operator) {
+    case ">=":
+      return actual >= expected;
+    case "<=":
+      return actual <= expected;
+    case ">":
+      return actual > expected;
+    case "<":
+      return actual < expected;
+    case "==":
+    case "=":
+      return actual === expected;
+    default:
+      return false;
+  }
+}

